val emptyClassifiedString = messages.map(_ => "")
val allContents = urls.flatMap { urlList =>
  urlList.foldLeft(emptyClassifiedString) { (acc, url) =>
    acc.flatMap { accContent =>
      getWebpage(url).map { newContent =>
        if (accContent.isEmpty) newContent else accContent + "\n" + newContent
      }
    }
  }
}

allContents.map { combinedContent =>
  if (combinedContent.isEmpty || combinedContent.contains("404 Not Found")) {
    sendChannelMessage("random", "No website content found to summarize.")
  } else {
    val summary = prompt(s"Summarize the following content in a single paragraph:\n$combinedContent")
    sendChannelMessage("random", summary)
  }
}

